  font-size: 0.9rem;
  margin-bottom: 15px;
  display: flex;
  gap: 15px;
}

.post-meta i {
  margin-right: 5px;
}

.post-content {
  color: #666;
  margin-bottom: 15px;
  line-height: 1.6;
}

.post-more a {
  display: inline-flex;
  align-items: center;
  color: var(--theme-color);
  font-size: 0.9rem;
}

.post-more i {
  margin-left: 5px;
  transition: transform 0.2s;
}

.post-more a:hover i {
  transform: translateX(3px);
}

.post-cover {
  flex: 0 0 200px;
  height: 150px;
  overflow: hidden;
  border-radius: 8px;
}

.post-cover img {
  width: 100%;
  height: 100%;
