/* 资源页面样式 */
.resource-container {
  margin: 0 auto;
  padding: 20px 0;
}

/* 标题区域 */
.section-title {
  text-align: center;
  margin: 30px 0;
}

.section-title h1 {
  font-size: 2rem;
  color: #444;
  margin: 0 0 10px 0;
}

.section-title p {
  color: #777;
  margin: 0;
  font-size: 1rem;
}

/* 分类过滤器 */
.filter-tabs {
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  margin: 30px 0;
}

.filter-tab {
  padding: 8px 18px;
  margin: 5px;
  background: #eee;
  border: none;
  border-radius: 20px;
  font-size: 0.9rem;
  color: #555;
  cursor: pointer;
  transition: all 0.2s;
}

.filter-tab:hover {
  background: #e0e0e0;
}

.filter-tab.active {
  background: #555;
  color: white;
}

/* 资源网格 */
.resource-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
  gap: 16px;
  padding: 10px 0;
  min-height: 200px;
}

/* 资源卡片 */
.resource-card {
  background: var(--card-bg, white);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: 0 3px 8px rgba(0, 0, 0, 0.05);
  position: relative;
  border: 1px solid rgba(0, 0, 0, 0.03);
  transition: transform 0.3s, box-shadow 0.3s;
  display: flex;
  flex-direction: column;
}

.resource-card:hover {
  transform: translateY(-3px);
