// event-bus.js
class CrossAppEvent {
constructor() {
this.events = new Map();
}
on(eventName, callback) {
const handlers = this.events.get(eventName) || [];
handlers.push(callback);
this.events.set(eventName, handlers);
}
emit(eventName, payload) {
