### 9.2 Promise 超时处理
```javascript
function timeoutPromise(promise, timeout) {
    return Promise.race([
        promise,
        new Promise((_, reject) =>
            setTimeout(() => reject(new Error('Timeout')), timeout)
        )
    ]);
}
```

### 9.3 取消操作
```javascript
function createCancellablePromise(promise) {
    let isCancelled = false;

    const wrappedPromise = new Promise((resolve, reject) => {
        promise.then(
            value => isCancelled ? reject('Cancelled') : resolve(value),
            error => isCancelled ? reject('Cancelled') : reject(error)
        );
    });

    return {
        promise: wrappedPromise,
        cancel: () => { isCancelled = true; }
    };
}
```

## 10. 常见问题和陷阱

### 10.1 Promise 执行顺序
```javascript
// ❌ 错误理解：认为 Promise 中的所有操作都是异步的
console.log('1');
Promise.resolve().then(() => console.log('2'));
setTimeout(() => console.log('3'), 0);
console.log('4');
// 输出: 1, 4, 2, 3

// ⚠️ 特别注意：Promise 中的同步和异步操作
console.log('开始');
new Promise((resolve, reject) => {
    console.log('同步代码1'); // Promise 构造函数中的代码是同步执行的
    resolve('同步代码2');     // resolve/reject 是同步执行的
    console.log('同步代码3'); // 这行也会同步执行
}).then(msg => {
    console.log('异步微任务1'); // then 回调是异步微任务
}).then(() => {
    console.log('异步微任务2'); // 链式调用的 then 也是异步微任务
});
console.log('结束');

// 输出顺序：
// 开始
// 同步代码1
// 同步代码2
// 同步代码3
// 结束
// 异步微任务1
// 异步微任务2

// 更复杂的执行顺序示例
console.log('script start');

setTimeout(() => {
    console.log('setTimeout'); // 宏任务
}, 0);

Promise.resolve('Promise 1')
    .then(msg => {
        console.log(msg); // 微任务
        return 'Promise 2';
    })
    .then(msg => {
        console.log(msg); // 微任务
    });

Promise.resolve('Promise 3')
    .then(msg => {
        console.log(msg); // 微任务
    });

console.log('script end');

// 输出顺序：
// script start
// script end
// Promise 1
// Promise 3
// Promise 2
// setTimeout
```

### 10.1.1 Promise 中的同步和异步操作

1. **同步执行的部分**：
   - Promise 构造函数中的代码
   - resolve() 或 reject() 的调用
   - 直接在 Promise 中的代码

2. **异步微任务**：
   - .then() 的回调
   - .catch() 的回调
   - .finally() 的回调

3. **执行顺序规则**：
   ```javascript
   // 示例：混合同步和异步操作
   console.log('1 - 同步');

   new Promise((resolve) => {
       console.log('2 - 同步');
       resolve('3 - 同步');
       console.log('4 - 同步');
   })
   .then(msg => {
       console.log('5 - 异步微任务');
       return new Promise(resolve => {
           console.log('6 - 同步');
           resolve('7 - 同步');
       });
   })
   .then(msg => {
       console.log('8 - 异步微任务');
   });

   setTimeout(() => {
       console.log('9 - 异步宏任务');
   }, 0);

   console.log('10 - 同步');

   // 输出顺序：
   // 1 - 同步
   // 2 - 同步
   // 4 - 同步
   // 10 - 同步
   // 5 - 异步微任务
   // 6 - 同步
   // 8 - 异步微任务
   // 9 - 异步宏任务
   ```

4. **注意事项**：
   - Promise 构造函数是同步执行的
   - resolve/reject 的调用是同步的，但其触发的 then/catch 是异步的
   - 微任务优先于宏任务执行
   - 同一轮事件循环中的微任务会在下一个宏任务之前执行完

5. **实际应用示例**：
   ```javascript
   async function example() {
       console.log('1 - 同步');

       const p = new Promise(resolve => {
           console.log('2 - 同步');
           resolve('3 - 同步');
       });

       console.log('4 - 同步');

       await p; // await 后面的代码会被转换成 then 的回调（微任务）

       console.log('5 - 异步');
   }

   example();
   console.log('6 - 同步');

   // 输出顺序：
   // 1 - 同步
   // 2 - 同步
   // 4 - 同步
   // 6 - 同步
   // 5 - 异步
   ```

