### 13.2 Promise 缓存优化
```javascript
class PromiseCache {
    constructor(ttl = 60000) { // 默认缓存时间 1 分钟
        this.cache = new Map();
        this.ttl = ttl;
    }

    async get(key, promiseFactory) {
        const cached = this.cache.get(key);
        if (cached && Date.now() - cached.timestamp < this.ttl) {
            return cached.data;
        }

        const data = await promiseFactory();
        this.cache.set(key, {
            data,
            timestamp: Date.now()
        });
        return data;
    }

    invalidate(key) {
        this.cache.delete(key);
    }

    clear() {
        this.cache.clear();
    }
}

